import AppLayout from '@/Layouts/AppLayout';
import TripBankFinancePanel from '@/Components/Banking/TripBankFinancePanel';
import MealPlanPanel from '@/Components/Recipes/MealPlanPanel';
import TripReservationImportPanel from '@/Components/Trips/TripReservationImportPanel';
import { Head, Link } from '@inertiajs/react';
import axios from 'axios';
import { ArrowDown, ArrowLeft, ArrowUp, Check, ChevronDown, Clock3, CloudDownload, Compass, Download, FileText, MapPin, Pencil, Plus, Save, Trash2, Wallet, WifiOff, X } from 'lucide-react';
import { useEffect, useMemo, useState } from 'react';

type ActivityType = 'activity' | 'transport' | 'stay' | 'reservation' | 'note' | 'checklist' | 'expense';
interface InboxItem { uuid: string; title: string; notes?: string; source_url?: string; kind: string; state?: string; trip_id?: number|null; trip_day_id?: number|null; trip_activity_id?: number|null; }
interface Activity { id: number; type: ActivityType; title: string; description?: string; starts_at?: string; ends_at?: string; place_name?: string; status: string; cost?: number; currency: string; inbox_items?: InboxItem[]; }
interface TripDay { id: number; date: string; title?: string; notes?: string; activities: Activity[]; inbox_items?: InboxItem[]; }
interface Trip { id: number; gallery_space_id:number; name: string; start_date: string; end_date: string; status: string; budget?: number; daily_budget_limit?: number; budget_profile?: 'economy' | 'balanced' | 'comfort'; currency: string; is_offline_available: boolean; }

const TYPES: Record<ActivityType, { label: string; icon: string; color: string }> = {
    activity: { label: 'Aktivita', icon: '✨', color: '#6c63ff' },
    transport: { label: 'Přesun', icon: '🚆', color: '#3b82f6' },
    stay: { label: 'Ubytování', icon: '🛏️', color: '#14b8a6' },
    reservation: { label: 'Rezervace', icon: '🎟️', color: '#f59e0b' },
    note: { label: 'Poznámka', icon: '📝', color: '#8b5cf6' },
    checklist: { label: 'Úkol', icon: '✅', color: '#22c55e' },
    expense: { label: 'Výdaj', icon: '💳', color: '#ef4444' },
};

export default function TripPlan({ tripId }: { tripId: number }) {
    const [trip, setTrip] = useState<Trip | null>(null);
    const [days, setDays] = useState<TripDay[]>([]);
    const [activeDayId, setActiveDayId] = useState<number | null>(null);
    const [loading, setLoading] = useState(true);
    const [offlineFallback, setOfflineFallback] = useState(false);
    const [loadError, setLoadError] = useState('');
    const [showAdd, setShowAdd] = useState(false);
    const [saving, setSaving] = useState(false);
    const [form, setForm] = useState({ type: 'activity' as ActivityType, title: '', starts_at: '', ends_at: '', place_name: '', cost: '' });

    const offlineKey = `maki-trip-offline-${tripId}`;
    const readOfflinePackage = () => {
        try {
            const saved = window.localStorage.getItem(offlineKey);
            return saved ? JSON.parse(saved) : null;
        } catch { return null; }
    };
    const storeOfflinePackage = async () => {
        const response = await axios.get(`/api/v1/trips/${tripId}/offline-package`);
        window.localStorage.setItem(offlineKey, JSON.stringify(response.data));
        return response.data;
    };
    const load = async () => {
        try {
            const response = await axios.get(`/api/v1/trips/${tripId}/plan`);
            setTrip(response.data.trip); setDays(response.data.days); setOfflineFallback(false); setLoadError('');
            setActiveDayId(previous => previous ?? response.data.days?.[0]?.id ?? null);
        } catch {
            const cached = readOfflinePackage();
            if (cached?.trip && Array.isArray(cached.days)) {
                setTrip(cached.trip); setDays(cached.days); setOfflineFallback(true);
                setActiveDayId(previous => previous ?? cached.days?.[0]?.id ?? null);
            } else setLoadError('Plán cesty se nepodařilo načíst. Připojte se k internetu a zkuste to znovu.');
        } finally { setLoading(false); }
    };
    useEffect(() => { load(); }, [tripId]);
    const activeDay = days.find(day => day.id === activeDayId) ?? null;
    const totalCost = useMemo(() => days.flatMap(day => day.activities).reduce((sum, activity) => sum + Number(activity.cost ?? 0), 0), [days]);

    const addActivity = async (event: React.FormEvent) => {
        event.preventDefault(); if (!activeDay || !form.title.trim()) return;
        setSaving(true);
        const payload = { ...form, starts_at: form.starts_at || null, ends_at: form.ends_at || null, place_name: form.place_name || null, cost: form.cost ? Number(form.cost) : null, currency: trip?.currency ?? 'CZK' };
        const response = await axios.post(`/api/v1/trips/${tripId}/plan/days/${activeDay.id}/activities`, payload);
        setDays(previous => previous.map(day => day.id === activeDay.id ? { ...day, activities: [...day.activities, response.data] } : day));
        setForm({ type: 'activity', title: '', starts_at: '', ends_at: '', place_name: '', cost: '' }); setShowAdd(false); setSaving(false);
    };
    const updateActivity = async (activity: Activity, patch: Record<string, unknown>) => {
        const response = await axios.patch(`/api/v1/trips/${tripId}/plan/activities/${activity.id}`, patch);
        setDays(previous => previous.map(day => ({ ...day, activities: day.activities.map(item => item.id === activity.id ? { ...item, ...response.data } : item) })));
    };
    const removeActivity = async (activity: Activity) => {
        if (!window.confirm(`Odebrat „${activity.title}“ z itineráře?`)) return;
        await axios.delete(`/api/v1/trips/${tripId}/plan/activities/${activity.id}`);
        setDays(previous => previous.map(day => ({ ...day, activities: day.activities.filter(item => item.id !== activity.id) })));
    };
    const moveActivity = async (index: number, direction: -1 | 1) => {
        if (!activeDay) return;
        const target = index + direction;
        if (target < 0 || target >= activeDay.activities.length) return;
        const previous = activeDay.activities;
        const reordered = [...previous];
        [reordered[index], reordered[target]] = [reordered[target], reordered[index]];
        setDays(items => items.map(day => day.id === activeDay.id ? { ...day, activities: reordered } : day));
        try {
            await axios.put(`/api/v1/trips/${tripId}/plan/days/${activeDay.id}/activities/reorder`, { order: reordered.map(item => item.id) });
        } catch (error: any) {
            setDays(items => items.map(day => day.id === activeDay.id ? { ...day, activities: previous } : day));
            alert(error?.response?.data?.message ?? 'Pořadí programu se nepodařilo uložit.');
        }
    };
    const updateStatus = async (status: string) => {
        await axios.patch(`/api/v1/trips/${tripId}`, { status });
        setTrip(previous => previous ? { ...previous, status } : previous);
    };
    const toggleOffline = async () => {
        const next = !trip.is_offline_available;
        await axios.patch(`/api/v1/trips/${tripId}`, { is_offline_available: next });
        if (next) await storeOfflinePackage(); else window.localStorage.removeItem(offlineKey);
        setTrip(previous => previous ? { ...previous, is_offline_available: next } : previous);
    };

    if (loadError) return <AppLayout><div className="mx-auto max-w-md p-6 text-center"><WifiOff className="mx-auto text-[var(--color-text-secondary)]" size={28}/><p className="mt-3 text-sm text-white">{loadError}</p><button onClick={() => { setLoading(true); setLoadError(''); load(); }} className="mt-4 min-h-10 rounded-xl border border-[var(--color-border)] px-4 text-sm text-[var(--color-accent)]">Načíst znovu</button></div></AppLayout>;
    if (loading || !trip) return <AppLayout><div className="flex h-full items-center justify-center"><div className="h-8 w-8 animate-spin rounded-full border-2 border-[var(--color-accent)] border-t-transparent" /></div></AppLayout>;

    return (
        <AppLayout>
            <Head title={`Plán · ${trip.name}`} />
            <div className="min-h-full pb-24">
                <header className="sticky top-0 z-20 border-b border-[var(--color-border)] bg-[var(--color-bg-primary)]/90 px-3 py-3 backdrop-blur-xl sm:px-6">
                    <div className="mx-auto flex max-w-6xl items-center gap-3">
                        <Link href="/trips" className="flex h-11 w-11 shrink-0 items-center justify-center rounded-xl border border-[var(--color-border)] text-[var(--color-text-secondary)] hover:text-white"><ArrowLeft size={18} /></Link>
                        <div className="min-w-0 flex-1"><p className="text-[10px] uppercase tracking-wider text-[var(--color-text-secondary)]">Workspace cesty</p><h1 className="truncate font-semibold text-white">{trip.name}</h1></div>
                        <div className="relative hidden sm:block"><select disabled={offlineFallback} value={trip.status} onChange={event => updateStatus(event.target.value)} className="min-h-10 appearance-none rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-card)] pl-3 pr-9 text-xs text-white disabled:opacity-50"><option value="draft">Návrh</option><option value="planned">Naplánováno</option><option value="active">Probíhá</option><option value="completed">Dokončeno</option><option value="archived">Archivováno</option></select><ChevronDown size={13} className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2" /></div>
                        <button disabled={offlineFallback} onClick={toggleOffline} title="Dostupnost bez internetu" className={`flex min-h-10 min-w-10 items-center justify-center rounded-xl border disabled:opacity-50 ${trip.is_offline_available ? 'border-green-500/40 bg-green-500/10 text-green-400' : 'border-[var(--color-border)] text-[var(--color-text-secondary)]'}`}><CloudDownload size={16} /></button>
                        <Link href={`/trips/${trip.id}/now`} className="flex min-h-10 items-center gap-2 rounded-xl bg-[var(--color-accent)] px-3 text-xs font-medium text-white"><Compass size={15}/><span className="hidden sm:inline">Právě teď</span></Link>
                        <div className="hidden items-center gap-2 rounded-xl bg-[var(--color-bg-card)] px-3 py-2 sm:flex"><Wallet size={14} className="text-[var(--color-accent)]" /><div><p className="text-[9px] text-[var(--color-text-secondary)]">Plánováno</p><p className="text-xs font-semibold text-white">{totalCost.toLocaleString('cs-CZ')} {trip.currency}</p></div></div>
                    </div>
                </header>

                <main className="mx-auto max-w-6xl p-3 sm:p-6">
                    {offlineFallback && <div className="mb-4 flex items-start gap-2 rounded-2xl border border-amber-400/25 bg-amber-500/10 p-3 text-xs text-amber-100"><WifiOff size={16} className="mt-0.5 shrink-0"/><span><strong>Pracujete z uložené cestovní karty.</strong> Změny jsou při výpadku připojení vypnuté; po návratu online se načte aktuální plán.</span></div>}
                    <div className={offlineFallback ? 'pointer-events-none select-none opacity-75' : ''}>
                    <div className="mb-5 flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                        {days.map((day, index) => <button key={day.id} onClick={() => setActiveDayId(day.id)} className={`min-w-[112px] shrink-0 rounded-2xl border p-3 text-left transition ${day.id === activeDayId ? 'border-[var(--color-accent)] bg-[var(--color-accent)]/15' : 'border-[var(--color-border)] bg-[var(--color-bg-card)]'}`}><p className="text-[10px] text-[var(--color-text-secondary)]">Den {index + 1}</p><p className="mt-0.5 text-sm font-medium text-white">{new Date(`${day.date}T12:00:00`).toLocaleDateString('cs-CZ', { weekday: 'short', day: 'numeric', month: 'numeric' })}</p><p className="mt-1 text-[9px] text-[var(--color-text-secondary)]">{day.activities.length} bloků</p></button>)}
                    </div>

                    <MealPlanPanel tripId={trip.id} days={days} onChanged={load}/>

                    <TripBankFinancePanel tripId={trip.id} gallerySpaceId={trip.gallery_space_id} currency={trip.currency}/>

                    <TripReservationImportPanel tripId={trip.id} days={days} currency={trip.currency} onChanged={load}/>

                    {activeDay && <div className="grid gap-5 lg:grid-cols-[minmax(0,1fr)_280px]">
                        <section>
                            <div className="mb-3 flex items-end justify-between"><div><p className="text-xs text-[var(--color-text-secondary)]">{new Date(`${activeDay.date}T12:00:00`).toLocaleDateString('cs-CZ', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</p><h2 className="text-xl font-bold text-white">{activeDay.title || 'Plán dne'}</h2></div><button onClick={() => setShowAdd(true)} className="flex min-h-11 items-center gap-2 rounded-xl bg-[var(--color-accent)] px-4 text-xs font-medium text-white"><Plus size={15} /> Přidat blok</button></div>

                            <div className="space-y-2">
                                {activeDay.inbox_items?.map(item => item.source_url?<a key={item.uuid} href={item.source_url} target="_blank" rel="noreferrer" className="block rounded-xl border border-sky-500/30 bg-sky-500/5 p-3 text-xs text-sky-100 hover:border-sky-400"><span className="mr-2">📎</span>{item.title}<span className="ml-2 text-sky-200/70">Podklad pro tento den</span></a>:<div key={item.uuid} className="rounded-xl border border-sky-500/30 bg-sky-500/5 p-3 text-xs text-sky-100"><span className="mr-2">📝</span>{item.title}<span className="ml-2 text-sky-200/70">Podklad pro tento den</span></div>)}
                                {activeDay.activities.length === 0 && !showAdd && <button onClick={() => setShowAdd(true)} className="flex min-h-40 w-full flex-col items-center justify-center rounded-3xl border border-dashed border-[var(--color-border)] text-[var(--color-text-secondary)] hover:border-[var(--color-accent)]"><Plus size={28} /><span className="mt-2 text-sm text-white">Sestavit první část dne</span><span className="mt-1 text-xs">Aktivita, přesun, rezervace, poznámka nebo výdaj</span></button>}
                                {activeDay.activities.map((activity, index) => <ActivityBlock key={activity.id} activity={activity} onUpdate={patch => updateActivity(activity, patch)} onRemove={() => removeActivity(activity)} onMoveUp={() => moveActivity(index, -1)} onMoveDown={() => moveActivity(index, 1)} canMoveUp={index > 0} canMoveDown={index < activeDay.activities.length - 1} />)}
                                {showAdd && <ActivityForm form={form} setForm={setForm} onSubmit={addActivity} onClose={() => setShowAdd(false)} saving={saving} />}
                            </div>
                        </section>

                        <aside className="space-y-3">
                            <div className="rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-card)] p-4"><p className="text-xs font-semibold text-white">Přehled dne</p><div className="mt-3 space-y-2 text-xs text-[var(--color-text-secondary)]"><div className="flex justify-between"><span>Bloků</span><span className="text-white">{activeDay.activities.length}</span></div><div className="flex justify-between"><span>Dokončeno</span><span className="text-white">{activeDay.activities.filter(item => item.status === 'done').length}</span></div><div className="flex justify-between"><span>Rozpočet</span><span className="text-white">{activeDay.activities.reduce((sum, item) => sum + Number(item.cost ?? 0), 0).toLocaleString('cs-CZ')} {trip.currency}</span></div></div></div>
                            <TripOfflinePackage tripId={trip.id} offlineKey={offlineKey} />
                             <TripPlanningPanel tripId={trip.id} currency={trip.currency} />
                            <TripTravelPanel trip={trip} days={days} activeDayId={activeDayId} />
                             <TripInboxReferencesPanel tripId={trip.id} gallerySpaceId={trip.gallery_space_id} day={activeDay} onAssigned={load} />
                             <TripMemoryPanel trip={trip} />
                            <TripReflectionPanel trip={trip} />
                             <LowCostFinancePanel trip={trip} />
                            <TripReadiness tripId={trip.id} />
                            <TripPackingPanel tripId={trip.id} />
                            <VehicleCostPanel tripId={trip.id} currency={trip.currency} />
                            <EmergencyCard tripId={trip.id} />
                            <div className="rounded-2xl border border-[var(--color-border)] bg-gradient-to-br from-[var(--color-accent)]/15 to-transparent p-4"><p className="text-xs font-semibold text-white">Tip</p><p className="mt-1 text-xs leading-relaxed text-[var(--color-text-secondary)]">Bloky drží rezervace, časy, místa i výdaje pohromadě. Na cestě se tento plán promění v kartu „Právě teď“.</p></div>
                        </aside>
                    </div>}
                    </div>
                </main>
            </div>
        </AppLayout>
    );
}

type OfflinePackage = {
    generated_at?: string;
    trip: Trip;
    days: TripDay[];
    documents?: Array<{ title:string; type?:string; reference?:string|null; expires_on?:string|null }>;
    reservations?: Array<{ title:string; type?:string; provider?:string|null; reference?:string|null; starts_at?:string|null; ends_at?:string|null; origin?:string|null; destination?:string|null; place_name?:string|null; amount?:number|null; currency?:string|null }>;
    emergency_card?: { accommodation_name?:string|null; accommodation_address?:string|null; accommodation_phone?:string|null; insurance_provider?:string|null; insurance_number?:string|null } | null;
    selected_route?: { name?:string|null; title?:string|null; origin?:string|null; destination?:string|null; duration_minutes?:number|null; price?:number|null; currency?:string|null } | null;
    preparation?: { actions?:Array<{title:string;due_at:string;priority:string}>; timeline?:Array<{title:string;at:string;status:string}>; score?:number };
};

function TripOfflinePackage({ tripId, offlineKey }: { tripId:number; offlineKey:string }) {
    const [snapshot, setSnapshot] = useState<OfflinePackage | null>(null);
    const [busy, setBusy] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        try { const saved = window.localStorage.getItem(offlineKey); if (saved) setSnapshot(JSON.parse(saved)); } catch { /* Corrupt local data is ignored. */ }
    }, [offlineKey]);

    const refresh = async () => {
        setBusy(true); setMessage('');
        try {
            const response = await axios.get(`/api/v1/trips/${tripId}/offline-package`);
            window.localStorage.setItem(offlineKey, JSON.stringify(response.data));
            setSnapshot(response.data); setMessage('Cestovní karta je uložená v tomto zařízení.');
            return response.data as OfflinePackage;
        } catch (error:any) {
            setMessage(error?.response?.data?.message ?? 'Kartu se nepodařilo aktualizovat.');
            return null;
        } finally { setBusy(false); }
    };

    const escapeHtml = (value: unknown) => String(value ?? '').replace(/[&<>'"]/g, char => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', "'":'&#039;', '"':'&quot;' }[char] ?? char));
    const download = async () => {
        const data = snapshot ?? await refresh();
        if (!data) return;
        const route = data.selected_route;
        const dayHtml = data.days.map((day, index) => `<section><h2>Den ${index + 1} · ${escapeHtml(new Date(`${day.date}T12:00:00`).toLocaleDateString('cs-CZ', { weekday:'long', day:'numeric', month:'long', year:'numeric' }))}</h2>${day.activities.length ? `<ol>${day.activities.map(activity => `<li><strong>${escapeHtml(activity.starts_at ? `${activity.starts_at} · ` : '')}${escapeHtml(activity.title)}</strong>${activity.place_name ? ` · ${escapeHtml(activity.place_name)}` : ''}${activity.description ? `<br><small>${escapeHtml(activity.description)}</small>` : ''}</li>`).join('')}</ol>` : '<p>Bez uložených bloků.</p>'}</section>`).join('');
        const docs = data.documents?.length ? `<section><h2>Doklady</h2><ul>${data.documents.map(doc => `<li><strong>${escapeHtml(doc.title)}</strong>${doc.expires_on ? ` · platnost ${escapeHtml(doc.expires_on)}` : ''}${doc.reference ? `<br><small>${escapeHtml(doc.reference)}</small>` : ''}</li>`).join('')}</ul></section>` : '';
        const reservations = data.reservations?.length ? `<section><h2>Potvrzené rezervace a jízdenky</h2><ul>${data.reservations.map(item => `<li><strong>${escapeHtml(item.title)}</strong>${item.starts_at ? ` · ${escapeHtml(new Date(item.starts_at).toLocaleString('cs-CZ'))}` : ''}${item.provider ? `<br><small>${escapeHtml(item.provider)}</small>` : ''}${item.origin || item.destination ? `<br><small>${escapeHtml(item.origin)} → ${escapeHtml(item.destination)}</small>` : ''}${item.place_name ? `<br><small>${escapeHtml(item.place_name)}</small>` : ''}${item.reference ? `<br><small>Kód: ${escapeHtml(item.reference)}</small>` : ''}${item.amount != null ? `<br><small>${escapeHtml(Number(item.amount).toLocaleString('cs-CZ'))} ${escapeHtml(item.currency ?? data.trip.currency)}</small>` : ''}</li>`).join('')}</ul></section>` : '';
        const emergency = data.emergency_card ? `<section><h2>Nouzová karta</h2>${data.emergency_card.accommodation_name ? `<p><strong>${escapeHtml(data.emergency_card.accommodation_name)}</strong><br>${escapeHtml(data.emergency_card.accommodation_address)}${data.emergency_card.accommodation_phone ? `<br>Telefon: ${escapeHtml(data.emergency_card.accommodation_phone)}` : ''}</p>` : ''}${data.emergency_card.insurance_provider ? `<p>Pojištění: ${escapeHtml(data.emergency_card.insurance_provider)}${data.emergency_card.insurance_number ? ` · ${escapeHtml(data.emergency_card.insurance_number)}` : ''}</p>` : ''}</section>` : '';
        const routeHtml = route ? `<section><h2>Vybraná cesta</h2><p><strong>${escapeHtml(route.title ?? route.name ?? 'Trasa')}</strong>${route.origin || route.destination ? `<br>${escapeHtml(route.origin)} → ${escapeHtml(route.destination)}` : ''}${route.duration_minutes ? ` · ${escapeHtml(route.duration_minutes)} min` : ''}${route.price ? ` · ${escapeHtml(Number(route.price).toLocaleString('cs-CZ'))} ${escapeHtml(route.currency ?? data.trip.currency)}` : ''}</p></section>` : '';
        const preparationHtml = data.preparation ? `<section><h2>Příprava cesty · ${escapeHtml(data.preparation.score ?? '–')}/100</h2>${data.preparation.actions?.length ? `<h3>Ještě zařídit</h3><ul>${data.preparation.actions.map(action => `<li><strong>${escapeHtml(action.title)}</strong> · do ${escapeHtml(new Date(action.due_at).toLocaleString('cs-CZ'))}</li>`).join('')}</ul>` : '<p>V přípravě není žádný otevřený krok.</p>'}${data.preparation.timeline?.filter(item => item.status !== 'past').length ? `<h3>Nejbližší časy</h3><ul>${data.preparation.timeline.filter(item => item.status !== 'past').slice(0,8).map(item => `<li><strong>${escapeHtml(item.title)}</strong> · ${escapeHtml(new Date(item.at).toLocaleString('cs-CZ'))}</li>`).join('')}</ul>` : ''}</section>` : '';
        const html = `<!doctype html><html lang="cs"><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${escapeHtml(data.trip.name)} · cestovní karta</title><style>body{font:16px/1.5 system-ui,sans-serif;max-width:760px;margin:auto;padding:24px;color:#18212f}h1{margin-bottom:0}h2{font-size:18px;margin:28px 0 8px;border-bottom:1px solid #d8dee8;padding-bottom:6px}h3{font-size:15px;margin:16px 0 6px}p{margin:6px 0}li{margin:10px 0}small{color:#4b5563}@media print{body{padding:0}section{break-inside:avoid}}</style><h1>${escapeHtml(data.trip.name)}</h1><p>${escapeHtml(data.trip.start_date)} – ${escapeHtml(data.trip.end_date)} · vytvořeno ${escapeHtml(new Date(data.generated_at ?? Date.now()).toLocaleString('cs-CZ'))}</p>${preparationHtml}${routeHtml}${dayHtml}${reservations}${docs}${emergency}<p><small>Offline cestovní karta z MAKI Gallery. Před cestou ji aktualizujte a uložte do telefonu nebo vytiskněte.</small></p></html>`;
        const url = URL.createObjectURL(new Blob([html], { type:'text/html;charset=utf-8' }));
        const link = document.createElement('a'); link.href = url; link.download = `${data.trip.name.replace(/[^a-z0-9áčďéěíňóřšťúůýž]+/gi, '-').replace(/^-|-$/g, '') || 'cesta'}-offline.html`; link.click();
        window.setTimeout(() => URL.revokeObjectURL(url), 1000);
        setMessage('Přenosná HTML karta byla stažena; v prohlížeči ji lze vytisknout i uložit jako PDF.');
    };

    return <section className="rounded-2xl border border-sky-400/25 bg-sky-500/5 p-4"><div className="flex items-start justify-between gap-3"><div><p className="flex items-center gap-1.5 text-xs font-semibold text-white"><FileText size={14} className="text-sky-200"/> Offline cestovní karta</p><p className="mt-1 text-[10px] leading-relaxed text-[var(--color-text-secondary)]">Itinerář, doklady, vybraná trasa a nouzové údaje v jednom souboru pro telefon i tisk.</p></div>{snapshot && <span className="shrink-0 rounded-full bg-emerald-500/15 px-2 py-1 text-[9px] text-emerald-200">uloženo</span>}</div><div className="mt-3 grid grid-cols-2 gap-2"><button type="button" disabled={busy} onClick={refresh} className="min-h-9 rounded-lg border border-sky-300/35 px-2 text-xs text-sky-100 disabled:opacity-50">{busy ? 'Ukládám…' : 'Aktualizovat'}</button><button type="button" disabled={busy} onClick={download} className="flex min-h-9 items-center justify-center gap-1 rounded-lg bg-sky-400/15 px-2 text-xs text-sky-100 disabled:opacity-50"><Download size={13}/> Stáhnout</button></div>{snapshot?.generated_at && <p className="mt-2 text-[9px] text-[var(--color-text-secondary)]">Poslední verze: {new Date(snapshot.generated_at).toLocaleString('cs-CZ')}</p>}{message && <p className={`mt-2 text-[10px] ${message.startsWith('Cestovní') || message.startsWith('Přenosná') ? 'text-emerald-200' : 'text-red-200'}`}>{message}</p>}</section>;
}

function TripTravelPanel({ trip, days, activeDayId }: { trip: Trip; days: TripDay[]; activeDayId:number|null }) {
    const [search, setSearch] = useState({from:'',to:'',date:trip.start_date,adults:'2'}); const [results, setResults] = useState<any[]>([]); const [busy, setBusy] = useState(false); const [message, setMessage] = useState(''); const [choices, setChoices] = useState<any[]>([]);
    const [stay, setStay] = useState({title:'',amount:'',reference:'',source_url:'',checkin:trip.start_date,checkout:trip.end_date,trip_day_id:String(activeDayId ?? days[0]?.id ?? '')});
    const loadChoices = () => axios.get(`/api/v1/trips/${trip.id}/travel-choices`).then(response => setChoices(response.data ?? [])).catch(() => setChoices([]));
    useEffect(() => { loadChoices(); }, [trip.id]);
    useEffect(() => setStay(current => ({...current,trip_day_id:String(activeDayId ?? days[0]?.id ?? '')})), [activeDayId, days]);
    const findTransport = async (event:React.FormEvent) => { event.preventDefault(); if (!search.from || !search.to) return; setBusy(true); setMessage(''); try { const response=await axios.get('/api/v1/tickets/search',{params:{from:search.from,to:search.to,date:search.date,adults:Number(search.adults)}}); setResults(response.data ?? []); } catch { setMessage('Spoje se nepodařilo načíst; zkuste změnit trasu nebo datum.'); } finally { setBusy(false); } };
    const selectTransport = async (item:any) => { setBusy(true); setMessage(''); try { await axios.post(`/api/v1/trips/${trip.id}/travel-choices/transport`, {title:`${item.carrier}: ${search.from} → ${search.to}`,provider:item.provider??item.carrier,source_url:item.book_url,amount:item.price,currency:item.currency,estimated_minutes:item.duration_min,transport_modes:item.modes??[item.mode].filter(Boolean),details:{result_id:item.result_id,departure:item.departure,arrival:item.arrival,transfers:item.transfers,source:item.source,data_source:item.data_source,legs:item.legs},is_selected:true}); setMessage('Doprava je vybraná a promítla se do varianty trasy i plánovaného rozpočtu.'); loadChoices(); } catch (error:any) { setMessage(error?.response?.data?.message ?? 'Spoj se nepodařilo uložit.'); } finally { setBusy(false); } };
    const openBooking = async () => { if (!search.to || !stay.checkin || !stay.checkout) { setMessage('Pro ubytování vyplňte cíl a termín.'); return; } try { const response = await axios.post(`/api/v1/trips/${trip.id}/booking-search`,{destination:search.to,checkin:stay.checkin,checkout:stay.checkout,adults:Number(search.adults)}); window.open(response.data.url,'_blank','noopener,noreferrer'); setStay(current => ({...current,source_url:response.data.url})); setMessage('Otevřeli jsme Booking.com; po výběru zapište cenu a potvrďte ubytování níže.'); } catch (error:any) { setMessage(error?.response?.data?.message ?? 'Vyhledání ubytování se nepodařilo připravit.'); } };
    const saveStay = async (event:React.FormEvent) => { event.preventDefault(); if (!stay.title || !stay.trip_day_id) return; setBusy(true); setMessage(''); try { await axios.post(`/api/v1/trips/${trip.id}/travel-choices/accommodation`,{...stay,trip_day_id:Number(stay.trip_day_id),amount:stay.amount?Number(stay.amount):null,provider:'Booking.com',is_selected:true}); setMessage('Ubytování je v itineráři, rozpočtu i kontrole rezervací.'); setStay(current=>({...current,title:'',amount:'',reference:''})); loadChoices(); } catch (error:any) { setMessage(error?.response?.data?.message ?? 'Ubytování se nepodařilo uložit.'); } finally { setBusy(false); } };
    return <section className="rounded-2xl border border-indigo-400/25 bg-indigo-500/5 p-4"><p className="text-xs font-semibold text-white">Cesta, doprava a ubytování</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Vybraná volba se jednou uloží do trasy, itineráře, plánovaného rozpočtu a dokladů.</p><form onSubmit={findTransport} className="mt-3 grid grid-cols-2 gap-2"><input required value={search.from} onChange={event=>setSearch({...search,from:event.target.value})} placeholder="Odkud" className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input required value={search.to} onChange={event=>setSearch({...search,to:event.target.value})} placeholder="Kam" className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="date" value={search.date} onChange={event=>setSearch({...search,date:event.target.value})} className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><button disabled={busy} className="min-h-9 rounded-lg border border-indigo-400/40 text-xs text-indigo-100 disabled:opacity-50">{busy?'Hledám…':'Najít dopravu'}</button></form>{results.length>0&&<div className="mt-3 max-h-36 space-y-1 overflow-auto">{results.slice(0,6).map((item,index)=><div key={index} className="flex items-center gap-2 rounded-lg bg-black/10 p-2"><span className="min-w-0 flex-1 truncate text-xs text-white">{item.icon} {item.carrier}{item.duration_min?` · ${item.duration_min} min`:''}{item.price!=null?` · ${Number(item.price).toLocaleString('cs-CZ')} ${item.currency}`:''}</span><button type="button" disabled={busy} onClick={()=>selectTransport(item)} className="shrink-0 text-[10px] text-indigo-200">Vybrat</button></div>)}</div>}<div className="mt-4 border-t border-indigo-300/20 pt-3"><div className="flex items-center justify-between"><p className="text-xs font-medium text-white">Ubytování</p><button type="button" onClick={openBooking} className="text-[10px] text-indigo-200 underline">Hledat na Booking.com</button></div><form onSubmit={saveStay} className="mt-2 grid grid-cols-2 gap-2"><input required value={stay.title} onChange={event=>setStay({...stay,title:event.target.value})} placeholder="Název ubytování" className="col-span-2 min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="date" value={stay.checkin} onChange={event=>setStay({...stay,checkin:event.target.value})} className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="date" value={stay.checkout} onChange={event=>setStay({...stay,checkout:event.target.value})} className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" value={stay.amount} onChange={event=>setStay({...stay,amount:event.target.value})} placeholder={`Cena ${trip.currency}`} className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input value={stay.reference} onChange={event=>setStay({...stay,reference:event.target.value})} placeholder="Kód rezervace" className="min-h-9 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><select value={stay.trip_day_id} onChange={event=>setStay({...stay,trip_day_id:event.target.value})} className="min-h-9 rounded-lg border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-2 text-xs text-white"><option value="">Den příjezdu</option>{days.map(day=><option key={day.id} value={day.id}>{new Date(`${day.date}T12:00:00`).toLocaleDateString('cs-CZ')}</option>)}</select><button disabled={busy} className="min-h-9 rounded-lg border border-indigo-400/40 text-xs text-indigo-100 disabled:opacity-50">Uložit pobyt</button></form></div>{choices.length>0&&<p className="mt-3 text-[10px] text-[var(--color-text-secondary)]">Vybráno: {choices.filter(choice=>choice.is_selected).map(choice=>choice.title).join(' · ')}</p>}{message&&<p className={`mt-2 text-[10px] ${message.includes('je ')||message.startsWith('Otevřeli')?'text-emerald-300':'text-red-300'}`}>{message}</p>}</section>;
}

function TripPlanningPanel({ tripId, currency }: { tripId: number; currency: string }) {
    const [data, setData] = useState<{ expenses:any[]; members:{id:number;name:string}[]; totals:{planned:number;actual:number;budget:number;currency:string}; route_variants:any[] } | null>(null);
    const [expense, setExpense] = useState({ title: '', amount: '', state: 'actual', paid_by_user_id: '' });
    const [variant, setVariant] = useState({ title: '', strategy: 'custom', estimated_minutes: '', estimated_cost: '' });
    const load = () => axios.get(`/api/v1/trips/${tripId}/planning`).then(r => setData(r.data)).catch(() => {});
    useEffect(() => { load(); }, [tripId]);
    const addExpense = async (e: React.FormEvent) => { e.preventDefault(); if (!expense.title || !expense.amount) return; await axios.post(`/api/v1/trips/${tripId}/expenses`, { ...expense, amount:Number(expense.amount), currency, paid_by_user_id: expense.paid_by_user_id ? Number(expense.paid_by_user_id) : null }); setExpense({title:'',amount:'',state:'actual',paid_by_user_id:''}); load(); };
    const addVariant = async (e: React.FormEvent) => { e.preventDefault(); if (!variant.title) return; await axios.post(`/api/v1/trips/${tripId}/route-variants`, { ...variant, estimated_minutes: variant.estimated_minutes ? Number(variant.estimated_minutes) : null, estimated_cost: variant.estimated_cost ? Number(variant.estimated_cost) : null, currency }); setVariant({title:'',strategy:'custom',estimated_minutes:'',estimated_cost:''}); load(); };
    const select = async (id:number) => { await axios.post(`/api/v1/trips/${tripId}/route-variants/${id}/select`); load(); };
    return <div className="rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-card)] p-4"><p className="text-xs font-semibold text-white">Rozpočet a varianty</p><div className="mt-3 grid grid-cols-2 gap-2 text-[10px] text-[var(--color-text-secondary)]"><span>Plán: <b className="text-white">{Number(data?.totals.planned ?? 0).toLocaleString('cs-CZ')} {currency}</b></span><span>Skutečnost: <b className="text-white">{Number(data?.totals.actual ?? 0).toLocaleString('cs-CZ')} {currency}</b></span></div><form onSubmit={addExpense} className="mt-3 space-y-2"><input value={expense.title} onChange={e=>setExpense({...expense,title:e.target.value})} placeholder="Výdaj" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><div className="flex gap-2"><input type="number" min="0" step="0.01" value={expense.amount} onChange={e=>setExpense({...expense,amount:e.target.value})} placeholder={currency} className="min-h-9 min-w-0 flex-1 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><select value={expense.state} onChange={e=>setExpense({...expense,state:e.target.value})} className="rounded-lg border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-xs text-white"><option value="actual">Skutečný</option><option value="planned">Plánovaný</option></select><button className="rounded-lg border border-[var(--color-border)] px-2 text-xs text-white">+</button></div><select value={expense.paid_by_user_id} onChange={e=>setExpense({...expense,paid_by_user_id:e.target.value})} className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-2 text-xs text-white"><option value="">Kdo zaplatil? (nezařadit do salda)</option>{data?.members?.map(member=><option key={member.id} value={member.id}>{member.name} · rozdělit rovným dílem</option>)}</select><p className="text-[10px] text-[var(--color-text-secondary)]">U skutečného výdaje se po výběru plátce podíl rozdělí automaticky mezi členy cesty.</p></form><div className="mt-3 max-h-28 space-y-1 overflow-auto">{data?.expenses.map(item=><div key={item.id} className="flex items-center justify-between gap-2 rounded-lg bg-black/10 px-2 py-1 text-[10px]"><span className="min-w-0 truncate text-[var(--color-text-secondary)]">{item.title}{item.paid_by_user_id ? ' · zaplaceno' : ''}{item.automation_source==='bank_transaction' ? ' · Revolut' : ''}</span><span className="shrink-0 text-white">{Number(item.amount).toLocaleString('cs-CZ')} {item.currency}</span></div>)}</div><form onSubmit={addVariant} className="mt-4 border-t border-[var(--color-border)] pt-3"><input value={variant.title} onChange={e=>setVariant({...variant,title:e.target.value})} placeholder="Název varianty trasy" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><div className="mt-2 flex gap-2"><input type="number" min="0" value={variant.estimated_minutes} onChange={e=>setVariant({...variant,estimated_minutes:e.target.value})} placeholder="min" className="min-h-9 min-w-0 flex-1 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><button className="rounded-lg border border-[var(--color-border)] px-2 text-xs text-white">Přidat</button></div></form><div className="mt-3 space-y-1">{data?.route_variants.map(item => <button key={item.id} onClick={()=>select(item.id)} className={`block w-full rounded-lg border p-2 text-left text-xs ${item.is_selected?'border-[var(--color-accent)] text-white':'border-[var(--color-border)] text-[var(--color-text-secondary)]'}`}>{item.is_selected?'✓ ':''}{item.title}{item.estimated_minutes?` · ${item.estimated_minutes} min`:''}</button>)}</div></div>;
}

function TripMemoryPanel({ trip }: { trip: Trip }) {
    type TripMedia = { id: number; uuid: string; media_type: string; file_name?: string; thumbnail_url?: string };
    type RecapAlbum = { uuid:string; title:string; media_count:number; story_blocks_count:number; memory_uuid?:string; memory?:{uuid:string;title:string}|null; curation?:{backup:{status:string;coverage_percent:number};quality:{missing_preview:number}} };
    const [open, setOpen] = useState(false); const [media, setMedia] = useState<TripMedia[]>([]); const [selected, setSelected] = useState<number[]>([]); const [title, setTitle] = useState(trip.name); const [note, setNote] = useState(''); const [saving, setSaving] = useState(false); const [suggesting, setSuggesting] = useState(false); const [message, setMessage] = useState(''); const [recap, setRecap] = useState<RecapAlbum|null>(null);
    const loadMedia = async (): Promise<TripMedia[]> => { const response = await axios.get(`/api/v1/trips/${trip.id}/media`); const items = response.data ?? []; setMedia(items); return items; };
    const loadRecap = async () => { try { const response = await axios.get(`/api/v1/trips/${trip.id}/recap-album`); setRecap(response.data.album ?? null); } catch (error:any) { if (error?.response?.status !== 503) setMessage(error?.response?.data?.message ?? 'Stav cestovního alba se nepodařilo načíst.'); } };
    const toggle = async () => {
        const next = !open; setOpen(next); setMessage('');
        if (!next) return;
        loadRecap();
        if (media.length) return;
        try { const items = await loadMedia(); setSelected(items.slice(0, 200).map(item => item.id)); }
        catch { setMessage('Fotky cesty se nepodařilo načíst.'); }
    };
    const importFromGallery = async () => {
        setSuggesting(true); setMessage('');
        try {
            const suggestions = await axios.get(`/api/v1/trips/${trip.id}/suggest-media`);
            const ids: number[] = suggestions.data.all_ids ?? [];
            if (!ids.length) { setMessage('V termínu cesty jsme v galerii nenašli další fotky.'); return; }
            await axios.post(`/api/v1/trips/${trip.id}/media`, { media_ids: ids });
            const items = await loadMedia(); setSelected(items.slice(0, 200).map(item => item.id));
            setMessage(`Přiřazeno ${ids.length} médií z termínu cesty; prvních ${Math.min(items.length, 200)} je vybráno do alba.`);
        } catch (error: any) { setMessage(error?.response?.data?.message ?? 'Fotky se nepodařilo přiřadit k cestě.'); }
        finally { setSuggesting(false); }
    };
    const save = async () => {
        if (!selected.length) return; setSaving(true); setMessage('');
        try { const response = await axios.post(`/api/v1/trips/${trip.id}/recap-album`, { title: title.trim() || trip.name, note: note || null, media_item_ids: selected }); setRecap(response.data); setMessage('Společné album, příběh i vzpomínka jsou propojené a uložené.'); }
        catch (error: any) { setMessage(error?.response?.data?.message ?? 'Cestovní album se nepodařilo uložit.'); }
        finally { setSaving(false); }
    };
    const isSuccess = message.startsWith('Společné') || message.startsWith('Přiřazeno');
    return <section className="rounded-2xl border border-fuchsia-500/25 bg-fuchsia-500/5 p-4">
        <div className="flex items-center justify-between gap-2">
            <div><p className="text-xs font-semibold text-white">Cestovní album a vzpomínka</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Cesta → galerie → denní příběh → společné zážitky.</p></div>
            <button onClick={toggle} className="min-h-9 rounded-lg border border-fuchsia-400/40 px-2 text-[10px] text-fuchsia-100">{open ? 'Zavřít' : recap ? 'Otevřít' : 'Vytvořit'}</button>
        </div>
        {open && <div className="mt-3 space-y-2">
            {recap && <div className="flex flex-wrap items-center gap-2 rounded-xl border border-emerald-400/25 bg-emerald-500/10 p-2 text-[10px] text-emerald-100">
                <span className="mr-auto">Album „{recap.title}“ · {recap.media_count} médií · {recap.story_blocks_count} částí příběhu{recap.curation ? ` · ${recap.curation.backup.coverage_percent} % originálů v cloudu${recap.curation.quality.missing_preview ? ` · ${recap.curation.quality.missing_preview} náhledů k opravě` : ''}` : ''}</span>
                <Link href={`/albums/${recap.uuid}`} className="rounded-lg border border-emerald-300/30 px-2 py-1">Výběr a bezpečí alba</Link>
            </div>}
            <input value={title} onChange={event => setTitle(event.target.value)} maxLength={160} className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white" placeholder="Název alba a vzpomínky"/>
            <textarea value={note} onChange={event => setNote(event.target.value)} maxLength={5000} rows={2} className="w-full rounded-lg border border-[var(--color-border)] bg-black/10 p-2 text-xs text-white" placeholder="Co si chceme připomenout? Text se použije v albu i vzpomínce."/>
            <button disabled={suggesting} onClick={importFromGallery} className="min-h-9 w-full rounded-lg border border-fuchsia-400/40 px-3 text-xs text-fuchsia-100 disabled:opacity-50">{suggesting ? 'Hledám v galerii…' : 'Najít fotky z termínu cesty'}</button>
            {media.length > 0 ? <div className="grid max-h-36 grid-cols-4 gap-1 overflow-auto">{media.map(item => <label key={item.id} title={item.file_name} className={`relative aspect-square cursor-pointer overflow-hidden rounded border ${selected.includes(item.id) ? 'border-fuchsia-300' : 'border-transparent opacity-55'}`}><input className="sr-only" type="checkbox" checked={selected.includes(item.id)} onChange={() => setSelected(current => current.includes(item.id) ? current.filter(id => id !== item.id) : current.length < 200 ? [...current, item.id] : current)}/>{item.thumbnail_url ? <img src={item.thumbnail_url} loading="lazy" alt="" className="h-full w-full object-cover"/> : <span className="flex h-full items-center justify-center text-sm">{item.media_type === 'video' ? '🎬' : '📷'}</span>}{selected.includes(item.id) && <span className="absolute right-0.5 top-0.5 rounded bg-fuchsia-500 px-1 text-[9px] text-white">✓</span>}</label>)}</div> : <p className="rounded-lg bg-black/10 p-2 text-[10px] text-[var(--color-text-secondary)]">Zatím nejsou vybraná média. Vyhledání používá jen obsah z data cesty a přidání vždy zůstává pod vaším potvrzením.</p>}
            <p className="text-[10px] text-[var(--color-text-secondary)]">Do alba lze vybrat až 200 médií. Při prvním vytvoření se připraví editovatelný příběh po dnech; pozdější synchronizace ruční úpravy nepřepíše.</p>
            <button disabled={!selected.length || saving} onClick={save} className="min-h-9 w-full rounded-lg bg-fuchsia-600 px-3 text-xs font-medium text-white disabled:opacity-50">{saving ? 'Propojuji cestu s galerií…' : `${recap ? 'Aktualizovat' : 'Vytvořit'} album, příběh a vzpomínku (${selected.length})`}</button>
            {message && <p className={`text-[10px] ${isSuccess ? 'text-emerald-300' : 'text-red-300'}`}>{message}</p>}
        </div>}
    </section>;
}

function TripReflectionPanel({ trip }: { trip: Trip }) {
    type Completion = { activities_total:number; activities_done:number; media_count:number; has_shared_memory:boolean; has_recap_album:boolean; actual_expenses:number; currency:string };
    const isOver = trip.status === 'completed' || new Date(`${trip.end_date}T23:59:59`).getTime() < Date.now();
    const [open, setOpen] = useState(false); const [loaded, setLoaded] = useState(false); const [saving, setSaving] = useState(false); const [message, setMessage] = useState('');
    const [revisit, setRevisit] = useState({ starts_at: '', reminder_minutes: '10080' }); const [revisitSaving, setRevisitSaving] = useState(false); const [revisitMessage, setRevisitMessage] = useState(''); const [revisitUuid, setRevisitUuid] = useState('');
    const [completion, setCompletion] = useState<Completion | null>(null);
    const [form, setForm] = useState({ rating: 0, highlight: '', gratitude: '', next_time: '' });
    const load = async () => { try { const response = await axios.get(`/api/v1/trips/${trip.id}/reflection`); const reflection = response.data.reflection; setCompletion(response.data.completion ?? null); if (reflection) setForm({ rating: Number(reflection.rating ?? 0), highlight: reflection.highlight ?? '', gratitude: reflection.gratitude ?? '', next_time: reflection.next_time ?? '' }); setLoaded(true); } catch (error:any) { setMessage(error?.response?.data?.message ?? 'Společné ohlédnutí se nepodařilo načíst.'); } };
    const toggle = async () => { const next = !open; setOpen(next); setMessage(''); if (next && !loaded) await load(); };
    const save = async (event: React.FormEvent) => { event.preventDefault(); setSaving(true); setMessage(''); try { await axios.put(`/api/v1/trips/${trip.id}/reflection`, { rating: form.rating || null, highlight: form.highlight || null, gratitude: form.gratitude || null, next_time: form.next_time || null }); setMessage('Společné ohlédnutí je uložené.'); await load(); } catch (error:any) { setMessage(error?.response?.data?.message ?? 'Ohlédnutí se nepodařilo uložit.'); } finally { setSaving(false); } };
    const scheduleRevisit = async () => { if (!revisit.starts_at) { setRevisitMessage('Vyberte prosím termín návratu.'); return; } setRevisitSaving(true); setRevisitMessage(''); try { const response = await axios.post(`/api/v1/trips/${trip.id}/revisit`, { starts_at: revisit.starts_at, reminder_minutes: Number(revisit.reminder_minutes || 0) }); setRevisitUuid(response.data.uuid); setRevisitMessage('Společný návrat je v kalendáři včetně připomenutí pro oba.'); } catch (error:any) { setRevisitMessage(error?.response?.data?.message ?? 'Návrat se nepodařilo naplánovat.'); } finally { setRevisitSaving(false); } };
    if (!isOver) return null;
    return <section className="rounded-2xl border border-orange-500/25 bg-orange-500/5 p-4"><div className="flex items-center justify-between gap-2"><div><p className="text-xs font-semibold text-white">Společné ohlédnutí</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Co stálo za zopakování a co příště uděláme jinak.</p></div><button onClick={toggle} className="min-h-9 rounded-lg border border-orange-400/40 px-2 text-[10px] text-orange-100">{open ? 'Zavřít' : 'Dopsat'}</button></div>{open && <div className="mt-3 space-y-3"><form onSubmit={save} className="space-y-2"><div className="rounded-lg bg-black/10 p-2 text-[10px] text-[var(--color-text-secondary)]">{completion ? <>{completion.activities_done}/{completion.activities_total} bodů itineráře dokončeno · {completion.media_count} fotek přiřazeno · {completion.has_shared_memory ? 'vzpomínka v galerii uložená' : 'vzpomínku lze uložit výše'}{completion.actual_expenses ? ` · ${Number(completion.actual_expenses).toLocaleString('cs-CZ')} ${completion.currency}` : ''}</> : 'Načítám kontext cesty…'}</div><div><p className="text-[10px] text-[var(--color-text-secondary)]">Jak se nám výlet povedl?</p><div className="mt-1 flex gap-1">{[1,2,3,4,5].map(value => <button key={value} type="button" onClick={() => setForm({...form,rating:value})} aria-label={`${value} z 5`} className={`min-h-9 min-w-9 rounded-lg text-base ${form.rating >= value ? 'bg-orange-400/20 text-orange-300' : 'bg-black/10 text-[var(--color-text-secondary)]'}`}>★</button>)}</div></div><textarea value={form.highlight} onChange={event => setForm({...form,highlight:event.target.value})} maxLength={2000} rows={2} className="w-full rounded-lg border border-[var(--color-border)] bg-black/10 p-2 text-xs text-white" placeholder="Nejhezčí moment výletu…"/><textarea value={form.gratitude} onChange={event => setForm({...form,gratitude:event.target.value})} maxLength={2000} rows={2} className="w-full rounded-lg border border-[var(--color-border)] bg-black/10 p-2 text-xs text-white" placeholder="Za co jsme rádi…"/><textarea value={form.next_time} onChange={event => setForm({...form,next_time:event.target.value})} maxLength={2000} rows={2} className="w-full rounded-lg border border-[var(--color-border)] bg-black/10 p-2 text-xs text-white" placeholder="Tip pro příště…"/><button disabled={saving} className="min-h-9 w-full rounded-lg border border-orange-400/40 text-xs text-orange-100 disabled:opacity-50">{saving ? 'Ukládám…' : 'Uložit společné ohlédnutí'}</button>{message && <p className={`text-[10px] ${message.startsWith('Společné') ? 'text-green-300' : 'text-red-300'}`}>{message}</p>}</form><div className="border-t border-orange-400/20 pt-3"><p className="text-xs font-medium text-white">Zopakovat si to spolu</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Nová společná akce naváže na tuto cestu, ale nezmění její historii ani rozpočet.</p><div className="mt-2 grid grid-cols-[minmax(0,1fr)_92px] gap-2"><input type="datetime-local" value={revisit.starts_at} onChange={event => setRevisit({...revisit,starts_at:event.target.value})} className="min-h-9 min-w-0 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" max="525600" value={revisit.reminder_minutes} onChange={event => setRevisit({...revisit,reminder_minutes:event.target.value})} aria-label="Připomenout minut předem" title="Minut předem" className="min-h-9 min-w-0 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/></div><button type="button" disabled={revisitSaving} onClick={scheduleRevisit} className="mt-2 min-h-9 w-full rounded-lg border border-orange-400/40 text-xs text-orange-100 disabled:opacity-50">{revisitSaving ? 'Plánuji…' : 'Naplánovat návrat s připomenutím'}</button>{revisitMessage && <p className={`mt-2 text-[10px] ${revisitUuid ? 'text-green-300' : 'text-red-300'}`}>{revisitMessage}{revisitUuid && <Link href={`/calendar/events/${revisitUuid}`} className="ml-1 underline">Otevřít v kalendáři</Link>}</p>}</div></div>}</section>;
}

function LowCostFinancePanel({ trip }: { trip: Trip }) {
    const [data, setData] = useState<any>(null);
    const [goal, setGoal] = useState({target_amount:'',saved_amount:'',monthly_contribution:''});
    const [plan, setPlan] = useState({budget_profile:trip.budget_profile ?? 'balanced',budget:trip.budget != null ? String(trip.budget) : '',daily_budget_limit:trip.daily_budget_limit != null ? String(trip.daily_budget_limit) : ''});
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState('');
    const load = () => axios.get(`/api/v1/trips/${trip.id}/finance-summary`).then(response => {
        setData(response.data);
        const advisor=response.data.advisor;
        if(advisor) setPlan({budget_profile:advisor.profile,budget:advisor.configured_budget != null ? String(advisor.configured_budget) : '',daily_budget_limit:advisor.configured_daily_limit != null ? String(advisor.configured_daily_limit) : ''});
        const current=response.data.savings_goal;
        if(current) setGoal({target_amount:String(current.target_amount),saved_amount:String(current.saved_amount),monthly_contribution:current.monthly_contribution?String(current.monthly_contribution):''});
    }).catch(() => setMessage('Rozpočet se nepodařilo načíst.'));
    useEffect(() => { load(); }, [trip.id]);
    const saveGoal = async (event:React.FormEvent) => { event.preventDefault(); if(!goal.target_amount) return; setSaving(true); setMessage(''); try { await axios.put(`/api/v1/trips/${trip.id}/savings-goal`, {target_amount:Number(goal.target_amount),saved_amount:Number(goal.saved_amount||0),monthly_contribution:goal.monthly_contribution?Number(goal.monthly_contribution):null,currency:trip.currency}); setMessage('Cestovní fond je uložený pro oba.'); await load(); } catch(error:any) { setMessage(error?.response?.data?.message ?? 'Fond se nepodařilo uložit.'); } finally { setSaving(false); } };
    const savePlan = async (event:React.FormEvent) => { event.preventDefault(); setSaving(true); setMessage(''); try { const response=await axios.put(`/api/v1/trips/${trip.id}/budget-plan`,{budget_profile:plan.budget_profile,budget:plan.budget===''?null:Number(plan.budget),daily_budget_limit:plan.daily_budget_limit===''?null:Number(plan.daily_budget_limit),apply_defaults:true,sync_calendar_tasks:true}); setData((current:any)=>({...current,advisor:response.data.advisor})); const automation=response.data.automation; setMessage(`Low-cost plán je propojený${automation.limits_applied ? ` · doplněno ${automation.limits_applied} limitů` : ''}${automation.calendar_tasks.created ? ` · ${automation.calendar_tasks.created} úkolů v kalendáři` : ''}.`); await load(); } catch(error:any) { setMessage(error?.response?.data?.message ?? 'Low-cost plán se nepodařilo uložit.'); } finally { setSaving(false); } };
    const advisor=data?.advisor;
    const memberName=(id:number)=>data?.members?.find((member:any)=>member.user_id===id)?.name ?? `Uživatel #${id}`;
    const statusClass=advisor?.status==='over'?'border-red-400/30 bg-red-500/5':advisor?.status==='ready'?'border-green-400/30 bg-green-500/5':'border-amber-400/30 bg-amber-500/5';
    return <section className={`rounded-2xl border p-4 ${statusClass}`}><div className="flex items-start justify-between gap-2"><div><p className="flex items-center gap-1.5 text-xs font-semibold text-white"><Wallet size={14}/> Rozpočet a vyrovnání</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Jeden plán pro dopravu, pobyt, program, auto i kalendář.</p></div>{advisor&&<span className={`shrink-0 rounded-full px-2 py-1 text-[10px] font-semibold ${advisor.status==='over'?'bg-red-500/15 text-red-200':advisor.status==='ready'?'bg-green-500/15 text-green-200':'bg-amber-500/15 text-amber-200'}`}>{advisor.health_score}/100</span>}</div>{advisor&&<><div className="mt-3 grid grid-cols-2 gap-2 text-[10px]"><div className="rounded-lg bg-black/10 p-2 text-[var(--color-text-secondary)]">Odhad<br/><strong className="text-xs text-white">{Number(advisor.projected).toLocaleString('cs-CZ')} {trip.currency}</strong></div><div className="rounded-lg bg-black/10 p-2 text-[var(--color-text-secondary)]">Rozpočet<br/><strong className="text-xs text-white">{advisor.budget!=null?`${Number(advisor.budget).toLocaleString('cs-CZ')} ${trip.currency}`:'nenastaven'}</strong></div></div>{advisor.usage_percent!=null&&<div className="mt-2 h-1.5 overflow-hidden rounded-full bg-black/20"><div className={`h-full rounded-full ${advisor.usage_percent>=100?'bg-red-400':advisor.usage_percent>=80?'bg-amber-400':'bg-green-400'}`} style={{width:`${Math.min(100,advisor.usage_percent)}%`}}/></div>}<p className="mt-2 text-[10px] text-[var(--color-text-secondary)]">{advisor.days_count} dní · denní limit {advisor.daily_limit!=null?`${Number(advisor.daily_limit).toLocaleString('cs-CZ')} ${trip.currency}`:'nenastaven'} · {advisor.profile_label.toLowerCase()}</p></>}
        <form onSubmit={savePlan} className="mt-3 space-y-2"><select value={plan.budget_profile} onChange={event=>setPlan({...plan,budget_profile:event.target.value as Trip['budget_profile'] ?? 'balanced'})} className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-2 text-xs text-white"><option value="economy">Úsporně</option><option value="balanced">Vyváženě</option><option value="comfort">Pohodlně</option></select><div className="grid grid-cols-2 gap-2"><input type="number" min="0" step="0.01" value={plan.budget} onChange={event=>setPlan({...plan,budget:event.target.value})} placeholder={`Celkem ${trip.currency}`} className="min-h-9 min-w-0 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" step="0.01" value={plan.daily_budget_limit} onChange={event=>setPlan({...plan,daily_budget_limit:event.target.value})} placeholder={`Na den ${trip.currency}`} className="min-h-9 min-w-0 rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/></div><button disabled={saving} className="min-h-9 w-full rounded-lg border border-emerald-400/40 text-xs text-emerald-100 disabled:opacity-50">{saving?'Propojuji…':'Uložit a propojit plán'}</button></form>
        {advisor?.warnings?.length>0&&<div className="mt-3 space-y-1">{advisor.warnings.slice(0,4).map((item:any)=><div key={item.code} className={`rounded-lg p-2 text-[10px] ${item.severity==='danger'?'bg-red-500/10 text-red-200':'bg-amber-500/10 text-amber-100'}`}><strong>{item.title}</strong><br/><span className="opacity-80">{item.message}</span></div>)}</div>}
        {advisor?.recommendations?.length>0&&<div className="mt-3"><p className="text-[10px] font-medium text-white">Další nejlepší krok</p>{advisor.recommendations.slice(0,3).map((item:any)=><p key={item.code} className="mt-1 text-[10px] leading-relaxed text-[var(--color-text-secondary)]">• {item.title}</p>)}</div>}
        {advisor?.categories?.some((item:any)=>item.total>0)&&<div className="mt-3 space-y-1 border-t border-white/10 pt-3">{advisor.categories.filter((item:any)=>item.total>0||item.limit!=null).map((item:any)=><div key={item.category} className="flex items-center justify-between gap-2 text-[10px]"><span className={item.status==='over'?'text-red-200':item.status==='warning'?'text-amber-200':'text-[var(--color-text-secondary)]'}>{item.label}</span><span className="text-white">{Number(item.total).toLocaleString('cs-CZ')}{item.limit!=null?` / ${Number(item.limit).toLocaleString('cs-CZ')}`:''}</span></div>)}</div>}
        {advisor?.saved_place_suggestions?.length>0&&<div className="mt-3 border-t border-white/10 pt-3"><p className="text-[10px] font-medium text-white">Cenově vhodná uložená místa</p><div className="mt-1 flex flex-wrap gap-1">{advisor.saved_place_suggestions.map((place:any)=><Link key={place.id} href={`/places/${place.id}`} className="rounded-full bg-sky-500/10 px-2 py-1 text-[10px] text-sky-200">{place.name} · {'€'.repeat(place.price_level)}</Link>)}</div></div>}
        <div className="mt-3 space-y-1 border-t border-white/10 pt-3 text-[10px] text-[var(--color-text-secondary)]">{data?.members?.map((member:any)=><p key={member.user_id}><span className="text-white">{member.name}</span>: zaplaceno {member.paid.toLocaleString('cs-CZ')} · podíl {member.owed.toLocaleString('cs-CZ')} {trip.currency}</p>)}{data?.proposals?.map((proposal:any,index:number)=><p key={index} className="rounded-lg bg-green-500/10 p-2 text-green-200">{memberName(proposal.from_user_id)} → {memberName(proposal.to_user_id)}: {proposal.amount.toLocaleString('cs-CZ')} {trip.currency}</p>)}{data?.unassigned_expense_ids?.length>0&&<p className="text-amber-300">Některé výdaje nemají plátce a nejsou v saldu.</p>}</div>
        <form onSubmit={saveGoal} className="mt-3 grid grid-cols-3 gap-1"><input required type="number" min="0" value={goal.target_amount} onChange={event=>setGoal({...goal,target_amount:event.target.value})} placeholder="Cíl" title="Cíl fondu" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" value={goal.saved_amount} onChange={event=>setGoal({...goal,saved_amount:event.target.value})} placeholder="Uloženo" title="Aktuálně uloženo" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" value={goal.monthly_contribution} onChange={event=>setGoal({...goal,monthly_contribution:event.target.value})} placeholder="Měsíčně" title="Měsíční příspěvek" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><button disabled={saving} className="col-span-3 min-h-9 rounded-lg border border-[var(--color-border)] text-xs text-[var(--color-accent)] disabled:opacity-50">Uložit cestovní fond</button></form>{message&&<p className={`mt-2 text-[10px] ${message.includes('uložen')||message.startsWith('Low-cost')?'text-green-300':'text-red-300'}`}>{message}</p>}</section>;
}

function EmergencyCard({ tripId }: { tripId: number }) {
    const [card,setCard]=useState<any>(null); const [editing,setEditing]=useState(false); const [form,setForm]=useState({accommodation_name:'',accommodation_address:'',accommodation_phone:'',insurance_provider:'',insurance_number:'',notes:''});
    const load=()=>axios.get(`/api/v1/trips/${tripId}/emergency-card`).then(r=>{setCard(r.data);if(r.data)setForm({accommodation_name:r.data.accommodation_name??'',accommodation_address:r.data.accommodation_address??'',accommodation_phone:r.data.accommodation_phone??'',insurance_provider:r.data.insurance_provider??'',insurance_number:r.data.insurance_number??'',notes:r.data.notes??''});}).catch(()=>{});
    useEffect(()=>{load();},[tripId]);
    const save=async(e:React.FormEvent)=>{e.preventDefault();await axios.put(`/api/v1/trips/${tripId}/emergency-card`,form);setEditing(false);load();};
    return <div className="rounded-2xl border border-amber-500/30 bg-amber-500/5 p-4"><div className="flex items-center justify-between"><p className="text-xs font-semibold text-white">Nouzová karta</p><button onClick={()=>setEditing(!editing)} className="text-xs text-amber-300">{editing?'Zavřít':'Upravit'}</button></div>{editing?<form onSubmit={save} className="mt-3 space-y-2"><input value={form.accommodation_name} onChange={e=>setForm({...form,accommodation_name:e.target.value})} placeholder="Ubytování" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><textarea value={form.accommodation_address} onChange={e=>setForm({...form,accommodation_address:e.target.value})} placeholder="Adresa" className="w-full rounded-lg border border-[var(--color-border)] bg-black/10 p-2 text-xs text-white"/><input value={form.accommodation_phone} onChange={e=>setForm({...form,accommodation_phone:e.target.value})} placeholder="Telefon ubytování" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input value={form.insurance_provider} onChange={e=>setForm({...form,insurance_provider:e.target.value})} placeholder="Pojišťovna" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input value={form.insurance_number} onChange={e=>setForm({...form,insurance_number:e.target.value})} placeholder="Číslo pojištění" className="min-h-9 w-full rounded-lg border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><button className="rounded-lg border border-amber-500/40 px-2 py-1 text-xs text-amber-200">Uložit kartu</button></form>:<div className="mt-2 space-y-1 text-xs text-[var(--color-text-secondary)]">{card?<><p className="text-white">{card.accommodation_name||'Ubytování není vyplněno'}</p>{card.accommodation_address&&<p>{card.accommodation_address}</p>}{card.accommodation_phone&&<a className="text-amber-300" href={`tel:${card.accommodation_phone}`}>{card.accommodation_phone}</a>}{card.insurance_provider&&<p>Pojištění: {card.insurance_provider}</p>}</>:<p>Doplňte ubytování, pojištění a nouzové kontakty pro offline použití.</p>}</div>}</div>;
}

function TripReadiness({ tripId }: { tripId: number }) {
    const [data,setData]=useState<any>(null);
    const [members,setMembers]=useState<Array<{id:number;name:string}>>([]);
    const [limit,setLimit]=useState({category:'food',amount:''});
    const [document,setDocument]=useState({type:'insurance',title:'',expires_on:'',status:'ready',assigned_to:''});
    const [syncing,setSyncing]=useState(false);
    const [message,setMessage]=useState('');
    const load=()=>Promise.allSettled([axios.get(`/api/v1/trips/${tripId}/readiness`),axios.get(`/api/v1/trips/${tripId}/packing-members`)]).then(([readiness,people])=>{if(readiness.status==='fulfilled')setData(readiness.value.data);if(people.status==='fulfilled')setMembers(people.value.data??[]);});
    useEffect(()=>{load();},[tripId]);
    const addLimit=async(e:React.FormEvent)=>{e.preventDefault();if(!limit.amount)return;await axios.put(`/api/v1/trips/${tripId}/budget-limits`,{category:limit.category,amount:Number(limit.amount)});setLimit({...limit,amount:''});load();};
    const addDocument=async(e:React.FormEvent)=>{e.preventDefault();if(!document.title)return;await axios.post(`/api/v1/trips/${tripId}/documents`,{...document,expires_on:document.expires_on||null,assigned_to:document.assigned_to?Number(document.assigned_to):null});setDocument({...document,title:'',expires_on:'',assigned_to:''});load();};
    const updateDocument=async(id:number,payload:Record<string,unknown>)=>{if(!data?.trip?.gallery_space_id)return;await axios.patch(`/api/v1/coordination/actions/trip_document/${id}`,{gallery_space_id:data.trip.gallery_space_id,...payload});await load();};
    const sync=async()=>{setSyncing(true);setMessage('');try{const response=await axios.post(`/api/v1/trips/${tripId}/preparation-timeline/sync`);setData((current:any)=>({...current,preparation:response.data.preparation}));const automation=response.data.automation;setMessage(automation.event_uuid?`Příprava je v kalendáři · ${automation.tasks_created} nových úkolů · ${automation.reminders_created} připomínek.`:'Cesta zatím není propojená s kalendářovou událostí.');await load();}catch(error:any){setMessage(error?.response?.data?.message??'Přípravu se nepodařilo synchronizovat.');}finally{setSyncing(false);}};
    const preparation=data?.preparation;
    const upcoming=preparation?.timeline?.filter((item:any)=>item.status!=='past').slice(0,4)??[];
    return <div className="rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-card)] p-4"><div className="flex items-start justify-between gap-2"><div><p className="text-xs font-semibold text-white">Doklady a připravenost</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Odjezd, přestupy, pobyt, platnosti a připomínky v jedné časové ose.</p></div><div className="shrink-0 text-right text-[10px]">{preparation&&<p className={preparation.status==='attention'?'text-amber-300':preparation.status==='ready'?'text-green-300':'text-white'}>příprava {preparation.score}/100</p>}{data?.budget_advisor&&<p className={data.budget_advisor.status==='over'?'text-red-300':data.budget_advisor.status==='ready'?'text-green-300':'text-amber-300'}>rozpočet {data.budget_advisor.health_score}/100</p>}</div></div>
        {preparation&&<div className="mt-3 rounded-xl bg-black/10 p-2"><div className="flex items-center justify-between"><p className="text-[10px] font-medium text-white">Co nás čeká</p><button disabled={syncing} onClick={sync} className="text-[10px] text-sky-200 disabled:opacity-50">{syncing?'Propojuji…':'Propojit s kalendářem'}</button></div><div className="mt-2 space-y-2">{upcoming.map((item:any)=><div key={item.key} className="flex gap-2 text-[10px]"><Clock3 size={12} className="mt-0.5 shrink-0 text-sky-300"/><div className="min-w-0"><p className="truncate text-white">{item.title}</p><p className="text-[var(--color-text-secondary)]">{new Date(item.at).toLocaleString('cs-CZ',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'})}{item.detail?` · ${item.detail}`:''}</p></div></div>)}{!upcoming.length&&<p className="text-[10px] text-[var(--color-text-secondary)]">V časové ose už není další budoucí bod.</p>}</div>{preparation.actions?.length>0&&<div className="mt-3 border-t border-white/10 pt-2">{preparation.actions.slice(0,4).map((item:any)=><p key={item.key} className={`mt-1 text-[10px] ${item.priority==='high'?'text-amber-200':'text-[var(--color-text-secondary)]'}`}>• {item.title}</p>)}</div>}{preparation.connection_checks?.some((item:any)=>item.risk!=='ok')&&<p className="mt-2 rounded-lg bg-amber-500/10 p-2 text-[10px] text-amber-100">Těsný přestup: {Math.min(...preparation.connection_checks.filter((item:any)=>item.risk!=='ok').map((item:any)=>item.minutes))} minut. Prověřte bezpečnější variantu.</p>}</div>}
        {data?.documents?.length>0&&<div className="mt-3 space-y-2">{data.documents.map((item:any)=><div key={item.id} className="grid gap-1 rounded-lg bg-black/10 p-2 sm:grid-cols-[minmax(0,1fr)_110px_auto] sm:items-center"><div className="min-w-0"><p className="truncate text-xs text-white">{item.title}</p><p className={`text-[10px] ${item.status==='missing'||item.status==='expired'?'text-red-300':'text-[var(--color-text-secondary)]'}`}>{item.status==='ready'?'připraveno':item.status==='missing'?'chybí':item.status==='expired'?'propadlé':'je potřeba'}{item.expires_on?` · ${item.expires_on}`:''}</p></div><select aria-label={`Kdo zařídí ${item.title}`} value={item.assigned_to??''} onChange={event=>updateDocument(item.id,{assigned_to:event.target.value?Number(event.target.value):null})} className="min-h-8 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="">Kdo zařídí?</option>{members.map(member=><option key={member.id} value={member.id}>{member.name}</option>)}</select>{item.status!=='ready'&&<button onClick={()=>updateDocument(item.id,{completed:true})} className="min-h-8 rounded border border-green-400/30 px-2 text-[10px] text-green-200">Připraveno</button>}</div>)}</div>}
        <div className="mt-2 space-y-1 text-xs text-[var(--color-text-secondary)]">{data?.time_conflicts?.map((item:any,index:number)=><p key={index} className="text-red-300">Kolize: {item.first} × {item.second}</p>)}{data?.expired_documents?.map((item:any)=><p key={item.id} className="text-red-300">Propadlý doklad: {item.title}</p>)}{!data?.time_conflicts?.length&&!data?.expired_documents?.length&&<p>Bez časových kolizí a propadlých dokladů.</p>}</div>
        <form onSubmit={addLimit} className="mt-3 flex gap-1"><select value={limit.category} onChange={e=>setLimit({...limit,category:e.target.value})} className="min-w-0 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="food">Jídlo</option><option value="transport">Doprava</option><option value="accommodation">Ubytování</option><option value="activities">Aktivity</option><option value="insurance">Pojištění</option><option value="other">Ostatní</option></select><input type="number" min="0" value={limit.amount} onChange={e=>setLimit({...limit,amount:e.target.value})} placeholder="Vlastní limit" className="min-w-0 flex-1 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><button className="text-xs text-[var(--color-accent)]">Uložit</button></form>
        <form onSubmit={addDocument} className="mt-2 grid grid-cols-2 gap-1"><select value={document.type} onChange={e=>setDocument({...document,type:e.target.value})} className="min-h-9 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="insurance">Pojištění</option><option value="id_card">Doklad</option><option value="passport">Pas</option><option value="ticket">Jízdenka</option><option value="booking">Rezervace</option></select><select value={document.status} onChange={e=>setDocument({...document,status:e.target.value})} className="min-h-9 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="ready">Připraveno</option><option value="required">Je potřeba</option><option value="missing">Chybí</option></select><input required value={document.title} onChange={e=>setDocument({...document,title:e.target.value})} placeholder="Název dokladu" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="date" value={document.expires_on} onChange={e=>setDocument({...document,expires_on:e.target.value})} aria-label="Platnost do" title="Platnost do" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><select value={document.assigned_to} onChange={event=>setDocument({...document,assigned_to:event.target.value})} className="min-h-9 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="">Kdo zařídí?</option>{members.map(member=><option key={member.id} value={member.id}>{member.name}</option>)}</select><button className="min-h-9 rounded-lg border border-[var(--color-border)] text-xs text-[var(--color-accent)]">Přidat doklad nebo rezervaci</button></form>{message&&<p className={`mt-2 text-[10px] ${message.startsWith('Příprava je')?'text-green-300':message.startsWith('Cesta zatím')?'text-amber-300':'text-red-300'}`}>{message}</p>}</div>;
}

function TripPackingPanel({ tripId }: { tripId: number }) {
    const [items, setItems] = useState<any[]>([]);
    const [members, setMembers] = useState<Array<{id:number;name:string}>>([]);
    const [title, setTitle] = useState('');
    const [category, setCategory] = useState('other');
    const [assignedTo, setAssignedTo] = useState('');
    const [busy, setBusy] = useState(false);
    const load = () => axios.get(`/api/v1/trips/${tripId}/packing-items`).then(response => setItems(response.data ?? [])).catch(() => {});
    useEffect(() => { load(); axios.get(`/api/v1/trips/${tripId}/packing-members`).then(response => setMembers(response.data ?? [])).catch(() => setMembers([])); }, [tripId]);
    const add = async (event: React.FormEvent) => { event.preventDefault(); if (!title.trim()) return; setBusy(true); try { await axios.post(`/api/v1/trips/${tripId}/packing-items`, { title: title.trim(), category, assigned_to: assignedTo ? Number(assignedTo) : null }); setTitle(''); setAssignedTo(''); load(); } finally { setBusy(false); } };
    const apply = async (template: string) => { setBusy(true); try { await axios.post(`/api/v1/trips/${tripId}/packing-items/apply-template`, { template }); load(); } finally { setBusy(false); } };
    const toggle = async (item: any) => { await axios.patch(`/api/v1/trips/${tripId}/packing-items/${item.id}`, { is_packed: !item.is_packed }); load(); };
    const assign = async (item: any, userId: string) => { await axios.patch(`/api/v1/trips/${tripId}/packing-items/${item.id}`, { assigned_to: userId ? Number(userId) : null }); load(); };
    const remove = async (item: any) => { if (confirm(`Odebrat „${item.title}“?`)) { await axios.delete(`/api/v1/trips/${tripId}/packing-items/${item.id}`); load(); } };
    const packed = items.filter(item => item.is_packed).length;
    const assigned = items.filter(item => item.assigned_to).length;
    return <section className="rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-card)] p-4"><div className="flex items-center justify-between"><div><p className="text-xs font-semibold text-white">Balicí seznam</p><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">Domluvené balení pro oba.</p></div><span className="text-right text-[10px] text-[var(--color-text-secondary)]">{packed}/{items.length}<br/>{assigned}/{items.length} přiřazeno</span></div><div className="mt-2 flex flex-wrap gap-1">{[['weekend','Víkend'],['flight','Letadlo'],['car','Auto'],['first_aid','Lékárnička']].map(([template,label]) => <button disabled={busy} key={template} onClick={() => apply(template)} className="min-h-8 rounded-lg border border-[var(--color-border)] px-2 text-[10px] text-[var(--color-text-secondary)] hover:text-white disabled:opacity-40">+ {label}</button>)}</div><form onSubmit={add} className="mt-3 grid grid-cols-[minmax(0,1fr)_92px] gap-1"><input value={title} onChange={event => setTitle(event.target.value)} placeholder="Přidat věc" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><select value={category} onChange={event => setCategory(event.target.value)} className="rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="other">Ostatní</option><option value="documents">Doklady</option><option value="health">Zdraví</option><option value="electronics">Elektronika</option><option value="car">Auto</option></select><select value={assignedTo} onChange={event => setAssignedTo(event.target.value)} className="min-h-9 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white"><option value="">Komukoli</option>{members.map(member => <option key={member.id} value={member.id}>{member.name}</option>)}</select><button disabled={busy} className="min-h-9 rounded border border-[var(--color-border)] text-xs text-[var(--color-accent)]">Přidat</button></form><div className="mt-3 max-h-72 space-y-2 overflow-auto">{items.map(item => <div key={item.id} className="rounded-lg bg-black/10 px-2 py-1.5"><div className="flex items-center gap-2"><button onClick={() => toggle(item)} className={`flex h-5 w-5 shrink-0 items-center justify-center rounded border ${item.is_packed ? 'border-green-400 bg-green-500/20 text-green-300' : 'border-[var(--color-text-secondary)]'}`}>{item.is_packed && <Check size={12}/>}</button><span className={`min-w-0 flex-1 truncate text-xs ${item.is_packed ? 'text-[var(--color-text-secondary)] line-through' : 'text-white'}`}>{item.title}{item.is_essential && <span className="ml-1 text-amber-300" title="Nezbytné">★</span>}</span><button onClick={() => remove(item)} className="p-1 text-[var(--color-text-secondary)] hover:text-red-300" aria-label="Odebrat položku"><Trash2 size={12}/></button></div><div className="mt-1 ml-7 flex items-center gap-2"><select value={item.assigned_to ?? ''} onChange={event => assign(item, event.target.value)} className="min-h-7 min-w-0 flex-1 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-[var(--color-text-secondary)]"><option value="">Kdo zabalí?</option>{members.map(member => <option key={member.id} value={member.id}>{member.name}</option>)}</select>{item.is_packed && <span className="shrink-0 text-[10px] text-green-300">{item.packed_by_name ? `Zabalil/a ${item.packed_by_name}` : 'Zabaleno'}</span>}</div></div>)}{!items.length && <p className="py-2 text-xs text-[var(--color-text-secondary)]">Zvolte šablonu nebo přidejte vlastní položku.</p>}</div></section>;
}

function VehicleCostPanel({ tripId, currency }: { tripId: number; currency: string }) {
    const [data, setData] = useState<{items:any[];summary:any}>({items:[],summary:{}});
    const [form, setForm] = useState({type:'fuel',title:'',amount:'',liters:'',distance_km:'',valid_until:''});
    const [saving, setSaving] = useState(false);
    const load = () => axios.get(`/api/v1/trips/${tripId}/vehicle-costs`).then(response => setData(response.data)).catch(() => {});
    useEffect(() => { load(); }, [tripId]);
    const add = async (event: React.FormEvent) => { event.preventDefault(); if (!form.title.trim() || !form.amount) return; setSaving(true); try { await axios.post(`/api/v1/trips/${tripId}/vehicle-costs`, {...form, amount:Number(form.amount), liters:form.liters ? Number(form.liters) : null, distance_km:form.distance_km ? Number(form.distance_km) : null, valid_until:form.valid_until || null, currency}); setForm({type:'fuel',title:'',amount:'',liters:'',distance_km:'',valid_until:''}); load(); } finally { setSaving(false); } };
    const remove = async (item:any) => { if (confirm(`Odebrat „${item.title}“?`)) { await axios.delete(`/api/v1/trips/${tripId}/vehicle-costs/${item.id}`); load(); } };
    const labels:Record<string,string> = {fuel:'Tankování',parking:'Parkování',vignette:'Známka',toll:'Mýto',maintenance:'Údržba',other:'Jiné'};
    return <section className="rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-card)] p-4"><div className="flex items-center justify-between"><p className="text-xs font-semibold text-white">Auto a parkování</p><span className="text-[10px] text-[var(--color-text-secondary)]">{Number(data.summary?.total ?? 0).toLocaleString('cs-CZ')} {currency}</span></div><p className="mt-1 text-[10px] text-[var(--color-text-secondary)]">{data.summary?.distance_km ? `${data.summary.distance_km} km · ${data.summary.cost_per_km} ${currency}/km` : 'Zapište tankování, parkování nebo dálniční známku.'}</p>{data.summary?.expired_vignettes?.length > 0 && <p className="mt-2 rounded-lg bg-red-500/10 p-2 text-[10px] text-red-200">Propadlá známka: {data.summary.expired_vignettes.map((item:any) => item.title).join(', ')}</p>}<form onSubmit={add} className="mt-3 space-y-2"><div className="flex gap-2"><select value={form.type} onChange={event => setForm({...form,type:event.target.value})} className="min-h-9 rounded border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-1 text-[10px] text-white">{Object.entries(labels).map(([key,label]) => <option key={key} value={key}>{label}</option>)}</select><input required value={form.title} onChange={event => setForm({...form,title:event.target.value})} placeholder="Např. benzín Brno" className="min-h-9 min-w-0 flex-1 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/></div><div className="grid grid-cols-3 gap-2"><input required type="number" min="0" step="0.01" value={form.amount} onChange={event => setForm({...form,amount:event.target.value})} placeholder={currency} className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" step="0.001" value={form.liters} onChange={event => setForm({...form,liters:event.target.value})} placeholder="litry" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/><input type="number" min="0" step="0.1" value={form.distance_km} onChange={event => setForm({...form,distance_km:event.target.value})} placeholder="km" className="min-h-9 min-w-0 rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/></div>{form.type === 'vignette' && <input type="date" value={form.valid_until} onChange={event => setForm({...form,valid_until:event.target.value})} className="min-h-9 w-full rounded border border-[var(--color-border)] bg-black/10 px-2 text-xs text-white"/>}<button disabled={saving} className="min-h-9 w-full rounded-lg border border-[var(--color-border)] text-xs text-[var(--color-accent)] disabled:opacity-40">{saving?'Ukládám…':'Přidat záznam'}</button></form><div className="mt-3 max-h-48 space-y-1 overflow-auto">{data.items.map(item => <div key={item.id} className="flex items-center gap-2 rounded-lg bg-black/10 px-2 py-1.5"><span className="min-w-0 flex-1 truncate text-xs text-white">{labels[item.type] ?? item.type}: {item.title}</span><span className="text-[10px] text-[var(--color-text-secondary)]">{Number(item.amount).toLocaleString('cs-CZ')} {item.currency}</span><button onClick={() => remove(item)} className="p-1 text-[var(--color-text-secondary)] hover:text-red-300" aria-label="Odebrat záznam"><Trash2 size={12}/></button></div>)}</div></section>;
}

function ActivityBlock({ activity, onUpdate, onRemove, onMoveUp, onMoveDown, canMoveUp, canMoveDown }: {
    activity: Activity; onUpdate: (patch: Record<string, unknown>) => Promise<void> | void; onRemove: () => void;
    onMoveUp: () => void; onMoveDown: () => void; canMoveUp: boolean; canMoveDown: boolean;
}) {
    const type = TYPES[activity.type] ?? TYPES.activity;
    const [editing, setEditing] = useState(false);
    const [savingEdit, setSavingEdit] = useState(false);
    const [edit, setEdit] = useState({ title: activity.title, starts_at: activity.starts_at?.slice(0, 5) ?? '', ends_at: activity.ends_at?.slice(0, 5) ?? '', place_name: activity.place_name ?? '', cost: activity.cost?.toString() ?? '' });
    const saveEdit = async (event: React.FormEvent) => {
        event.preventDefault(); if (!edit.title.trim()) return;
        setSavingEdit(true);
        await onUpdate({ title: edit.title.trim(), starts_at: edit.starts_at || null, ends_at: edit.ends_at || null, place_name: edit.place_name || null, cost: edit.cost ? Number(edit.cost) : null });
        setSavingEdit(false); setEditing(false);
    };

    if (editing) return <form onSubmit={saveEdit} className="rounded-2xl border border-[var(--color-accent)]/40 bg-[var(--color-bg-card)] p-4"><div className="grid gap-2 sm:grid-cols-2"><input required value={edit.title} onChange={e => setEdit({...edit,title:e.target.value})} className="min-h-11 rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-sm text-white sm:col-span-2" placeholder="Název"/><input type="time" value={edit.starts_at} onChange={e => setEdit({...edit,starts_at:e.target.value})} className="min-h-11 rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white"/><input type="time" value={edit.ends_at} onChange={e => setEdit({...edit,ends_at:e.target.value})} className="min-h-11 rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white"/><input value={edit.place_name} onChange={e => setEdit({...edit,place_name:e.target.value})} className="min-h-11 rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" placeholder="Místo"/><input type="number" min="0" value={edit.cost} onChange={e => setEdit({...edit,cost:e.target.value})} className="min-h-11 rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" placeholder="Cena"/></div><div className="mt-3 flex gap-2"><button disabled={savingEdit} className="flex min-h-11 flex-1 items-center justify-center gap-2 rounded-xl bg-[var(--color-accent)] text-xs text-white"><Save size={14}/>{savingEdit?'Ukládám…':'Uložit'}</button><button type="button" onClick={() => setEditing(false)} className="min-h-11 rounded-xl border border-[var(--color-border)] px-4 text-xs">Zrušit</button></div></form>;

    return <article className={`group flex flex-col gap-2 rounded-2xl border p-3 transition sm:flex-row ${activity.status === 'done' ? 'border-green-500/20 bg-green-500/5 opacity-70' : 'border-[var(--color-border)] bg-[var(--color-bg-card)]'}`}><div className="flex min-w-0 flex-1 gap-3"><div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-xl text-lg" style={{ backgroundColor: `${type.color}22` }}>{type.icon}</div><div className="min-w-0 flex-1"><div className="flex flex-wrap items-center gap-x-2"><p className={`font-medium text-white ${activity.status === 'done' ? 'line-through' : ''}`}>{activity.title}</p><span className="text-[9px] uppercase tracking-wider" style={{ color: type.color }}>{type.label}</span></div>{(activity.starts_at || activity.place_name) && <div className="mt-1 flex flex-wrap gap-3 text-[10px] text-[var(--color-text-secondary)]">{activity.starts_at && <span className="flex items-center gap-1"><Clock3 size={11}/>{activity.starts_at.slice(0,5)}{activity.ends_at?`–${activity.ends_at.slice(0,5)}`:''}</span>}{activity.place_name&&<span className="flex items-center gap-1"><MapPin size={11}/>{activity.place_name}</span>}</div>}{activity.description&&<p className="mt-2 text-xs text-[var(--color-text-secondary)]">{activity.description}</p>}{activity.inbox_items&&activity.inbox_items.length>0&&<div className="mt-2 flex flex-wrap gap-1">{activity.inbox_items.map(item=>item.source_url?<a key={item.uuid} href={item.source_url} target="_blank" rel="noreferrer" className="rounded-md border border-sky-400/25 bg-sky-500/10 px-2 py-1 text-[10px] text-sky-100">📎 {item.title}</a>:<span key={item.uuid} className="rounded-md border border-sky-400/20 bg-sky-500/5 px-2 py-1 text-[10px] text-sky-100">📝 {item.title}</span>)}</div>}{activity.cost!=null&&<p className="mt-2 text-[10px] font-medium text-amber-400">{Number(activity.cost).toLocaleString('cs-CZ')} {activity.currency}</p>}</div></div><div className="flex shrink-0 justify-end gap-1"><button disabled={!canMoveUp} onClick={onMoveUp} title="Posunout nahoru" className="flex h-9 w-9 items-center justify-center rounded-xl text-[var(--color-text-secondary)] hover:bg-white/5 disabled:opacity-20"><ArrowUp size={14}/></button><button disabled={!canMoveDown} onClick={onMoveDown} title="Posunout dolů" className="flex h-9 w-9 items-center justify-center rounded-xl text-[var(--color-text-secondary)] hover:bg-white/5 disabled:opacity-20"><ArrowDown size={14}/></button><button onClick={() => setEditing(true)} title="Upravit" className="flex h-9 w-9 items-center justify-center rounded-xl text-[var(--color-text-secondary)] hover:bg-white/5 hover:text-white"><Pencil size={14}/></button><button onClick={() => onUpdate({status:activity.status==='done'?'planned':'done'})} title="Dokončit" className="flex h-9 w-9 items-center justify-center rounded-xl text-[var(--color-text-secondary)] hover:bg-green-500/10 hover:text-green-400"><Check size={15}/></button><button onClick={onRemove} title="Odebrat" className="flex h-9 w-9 items-center justify-center rounded-xl text-[var(--color-text-secondary)] hover:bg-red-500/10 hover:text-red-400"><Trash2 size={14}/></button></div></article>;
}

function ActivityForm({ form, setForm, onSubmit, onClose, saving }: { form: any; setForm: (value: any) => void; onSubmit: (event: React.FormEvent) => void; onClose: () => void; saving: boolean }) {
    return <form onSubmit={onSubmit} className="rounded-2xl border border-[var(--color-accent)]/40 bg-[var(--color-bg-card)] p-4"><div className="mb-3 flex items-center justify-between"><p className="text-sm font-semibold text-white">Nový blok</p><button type="button" onClick={onClose} className="flex h-9 w-9 items-center justify-center rounded-xl"><X size={16} /></button></div><div className="grid gap-3 sm:grid-cols-2"><label className="text-[10px] text-[var(--color-text-secondary)]">Typ<select value={form.type} onChange={e => setForm({ ...form, type: e.target.value })} className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white">{Object.entries(TYPES).map(([key, value]) => <option key={key} value={key}>{value.icon} {value.label}</option>)}</select></label><label className="text-[10px] text-[var(--color-text-secondary)] sm:col-span-2">Název<input autoFocus required value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="Co se bude dít?" className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-sm text-white" /></label><label className="text-[10px] text-[var(--color-text-secondary)]">Od<input type="time" value={form.starts_at} onChange={e => setForm({ ...form, starts_at: e.target.value })} className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" /></label><label className="text-[10px] text-[var(--color-text-secondary)]">Do<input type="time" value={form.ends_at} onChange={e => setForm({ ...form, ends_at: e.target.value })} className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" /></label><label className="text-[10px] text-[var(--color-text-secondary)]">Místo<input value={form.place_name} onChange={e => setForm({ ...form, place_name: e.target.value })} placeholder="Adresa nebo název" className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" /></label><label className="text-[10px] text-[var(--color-text-secondary)]">Cena<input type="number" min="0" value={form.cost} onChange={e => setForm({ ...form, cost: e.target.value })} placeholder="0" className="mt-1 min-h-11 w-full rounded-xl border border-[var(--color-border)] bg-[var(--color-bg-secondary)] px-3 text-xs text-white" /></label></div><button disabled={saving} className="mt-4 min-h-11 w-full rounded-xl bg-[var(--color-accent)] text-sm font-medium text-white disabled:opacity-40">{saving ? 'Přidávám…' : 'Přidat do dne'}</button></form>;
}

function TripInboxReferencesPanel({ tripId, gallerySpaceId, day, onAssigned }: { tripId: number; gallerySpaceId:number; day: TripDay; onAssigned: () => Promise<void> }) {
    const [available, setAvailable] = useState<InboxItem[]>([]);
    const [savingUuid, setSavingUuid] = useState<string | null>(null);
    const [error, setError] = useState('');
    const [draft,setDraft] = useState({title:'',source_url:'',kind:'idea',promote:true});
    const loadAvailable = () => axios.get('/api/v1/calendar/inbox?state=inbox')
        .then(response => setAvailable(response.data.filter((item: InboxItem & { trip_id?: number | null }) => !item.trip_id || Number(item.trip_id) === tripId)))
        .catch(() => setAvailable([]));
    useEffect(() => { loadAvailable(); }, [tripId]);
    const assignToDay = async (item: InboxItem) => {
        setSavingUuid(item.uuid); setError('');
        try {
            await axios.patch(`/api/v1/calendar/inbox/${item.uuid}`, { trip_id: tripId, trip_day_id: day.id, trip_activity_id: null, state: 'assigned' });
            await Promise.all([onAssigned(), loadAvailable()]);
        } catch (requestError: any) {
            setError(requestError?.response?.data?.message ?? 'Podklad se nepodařilo přidat do dne.');
        } finally {
            setSavingUuid(null);
        }
    };
    const promote = async (item:InboxItem) => {
        setSavingUuid(item.uuid); setError('');
        try {
            await axios.post(`/api/v1/trips/${tripId}/plan/days/${day.id}/inbox/${item.uuid}/promote`);
            await Promise.all([onAssigned(),loadAvailable()]);
        } catch (requestError:any) {
            setError(requestError?.response?.data?.message ?? 'Podklad se nepodařilo převést do programu.');
        } finally { setSavingUuid(null); }
    };
    const capture = async (event:React.FormEvent) => {
        event.preventDefault(); if(!draft.title.trim())return; setSavingUuid('new');setError('');
        try {
            const response=await axios.post('/api/v1/calendar/inbox',{gallery_space_id:gallerySpaceId,trip_id:tripId,trip_day_id:day.id,title:draft.title.trim(),source_url:draft.source_url||null,kind:draft.kind});
            if(draft.promote) await axios.post(`/api/v1/trips/${tripId}/plan/days/${day.id}/inbox/${response.data.uuid}/promote`);
            setDraft({title:'',source_url:'',kind:'idea',promote:true});
            await Promise.all([onAssigned(),loadAvailable()]);
        } catch(requestError:any){setError(requestError?.response?.data?.message??'Podklad se nepodařilo uložit.');}
        finally{setSavingUuid(null);}
    };
    const dayItems = day.inbox_items ?? [];
    const activityItems = day.activities.flatMap(activity => (activity.inbox_items ?? []).map(item => ({ ...item, activity: activity.title })));
    const items = [...dayItems.map(item => ({ ...item, activity: 'Celý den' })), ...activityItems];
    return <section className="rounded-2xl border border-sky-500/25 bg-sky-500/5 p-4"><div><p className="text-xs font-semibold text-white">Podklady a rychlé nápady</p><p className="mt-1 text-[10px] leading-relaxed text-sky-100/65">Odkaz, rezervaci nebo poznámku uložte rovnou k tomuto dni. Může zůstat podkladem, nebo se ihned stát upravitelným blokem programu.</p></div><form onSubmit={capture} className="mt-3 space-y-2"><input required value={draft.title} onChange={event=>setDraft({...draft,title:event.target.value})} placeholder="Nápad, rezervace nebo poznámka" className="min-h-9 w-full rounded-lg border border-sky-400/20 bg-black/10 px-2 text-xs text-white"/><input type="url" value={draft.source_url} onChange={event=>setDraft({...draft,source_url:event.target.value})} placeholder="https://… (volitelné)" className="min-h-9 w-full rounded-lg border border-sky-400/20 bg-black/10 px-2 text-xs text-white"/><div className="grid grid-cols-2 gap-2"><select value={draft.kind} onChange={event=>setDraft({...draft,kind:event.target.value})} className="min-h-9 rounded-lg border border-sky-400/20 bg-[var(--color-bg-secondary)] px-2 text-[10px] text-white"><option value="idea">Nápad</option><option value="reservation">Rezervace</option><option value="note">Poznámka</option><option value="link">Odkaz</option></select><button disabled={savingUuid==='new'} className="rounded-lg bg-sky-600 px-2 text-[10px] text-white disabled:opacity-50">{savingUuid==='new'?'Ukládám…':'Uložit k dni'}</button></div><label className="flex items-start gap-2 text-[10px] text-sky-100/75"><input type="checkbox" checked={draft.promote} onChange={event=>setDraft({...draft,promote:event.target.checked})} className="mt-0.5"/><span>Současně přidat jako blok itineráře</span></label></form>{items.length > 0 && <div className="mt-3 border-t border-sky-400/20 pt-3"><p className="text-[10px] text-sky-100/70">U tohoto dne</p><div className="mt-2 space-y-2">{items.map(item => <div key={item.uuid} className="rounded-lg bg-black/10 px-2 py-2"><div className="flex items-center gap-2">{item.source_url?<a href={item.source_url} target="_blank" rel="noreferrer" className="min-w-0 flex-1 truncate text-xs text-sky-100 hover:text-white">📎 {item.title}</a>:<p className="min-w-0 flex-1 truncate text-xs text-sky-100">📝 {item.title}</p>}{item.activity==='Celý den'&&<button disabled={savingUuid===item.uuid} onClick={()=>promote(item)} className="shrink-0 rounded-md border border-sky-400/30 px-2 py-1 text-[9px] text-sky-100 disabled:opacity-50">Do programu</button>}</div><p className="mt-0.5 text-[9px] text-sky-200/60">{item.activity}</p></div>)}</div></div>}{available.length > 0 && <div className="mt-3 border-t border-sky-400/20 pt-3"><p className="text-[10px] text-sky-100/70">Nepřiřazené podklady</p><div className="mt-2 space-y-2">{available.slice(0, 6).map(item => <div key={item.uuid} className="rounded-lg bg-black/10 px-2 py-2"><p className="truncate text-xs text-sky-100">📎 {item.title}</p><div className="mt-2 flex gap-1"><button disabled={savingUuid===item.uuid} onClick={()=>assignToDay(item)} className="min-h-7 flex-1 rounded-md border border-sky-400/30 px-1 text-[9px] text-sky-100 disabled:opacity-50">Jen podklad</button><button disabled={savingUuid===item.uuid} onClick={()=>promote(item)} className="min-h-7 flex-1 rounded-md bg-sky-600/70 px-1 text-[9px] text-white disabled:opacity-50">Do programu</button></div></div>)}</div></div>}{error && <p className="mt-2 text-[10px] text-red-300">{error}</p>}</section>;
}
